import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { requireGarageAdminAccess } from "@/lib/auth-guards";
import { sendCampaign } from "@/lib/campaigns";

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const garageId = String(searchParams.get("garageId") || "").trim();

  if (!garageId) {
    return NextResponse.json({ error: "garageId is required" }, { status: 400 });
  }

  const guard = await requireGarageAdminAccess(request, garageId);
  if ("response" in guard) return guard.response;

  const campaigns = await prisma.campaign.findMany({
    where: { garageId },
    orderBy: { createdAt: "desc" },
  });

  return NextResponse.json(campaigns);
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const garageId = String(body.garageId || "").trim();
    const name = String(body.name || "").trim();
    const subject = String(body.subject || "").trim();
    const message = String(body.message || "").trim();
    const channel = String(body.channel || "EMAIL").toUpperCase();
    const targetAudience = String(body.targetAudience || "all").toLowerCase();
    const scheduledFor = body.scheduledFor ? new Date(body.scheduledFor) : null;

    if (!garageId || !name || !message) {
      return NextResponse.json(
        { error: "garageId, name, and message are required" },
        { status: 400 }
      );
    }

    const guard = await requireGarageAdminAccess(request, garageId);
    if ("response" in guard) return guard.response;

    if (channel !== "EMAIL") {
      return NextResponse.json(
        { error: "SMS campaigns are not enabled yet" },
        { status: 400 }
      );
    }

    const subjectValue = subject || name;

    const campaign = await prisma.campaign.create({
      data: {
        garageId,
        name,
        subject: subjectValue,
        message,
        channel,
        targetAudience,
        scheduledFor: scheduledFor || undefined,
        status: scheduledFor && scheduledFor > new Date() ? "SCHEDULED" : "SENDING",
      },
    });

    if (campaign.status === "SCHEDULED") {
      return NextResponse.json(campaign, { status: 201 });
    }

    await sendCampaign({
      campaignId: campaign.id,
      originHeader: request.headers.get("origin"),
    });

    const refreshed = await prisma.campaign.findUnique({
      where: { id: campaign.id },
    });

    return NextResponse.json(refreshed, { status: 201 });
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    return NextResponse.json(
      { error: "Failed to create campaign", details: message },
      { status: 500 }
    );
  }
}
