import { Resend } from "resend";
import crypto from "crypto";
import { prisma } from "@/lib/prisma";
import { getApiKey } from "@/app/api/admin/config/route";

const CAMPAIGN_COOLDOWN_DAYS = 7;
const SERVICE_DUE_DAYS = 180;
const INACTIVE_DAYS = 90;

export type CampaignAudience = "all" | "mot_expiring" | "service_due" | "inactive";

const getOrigin = (originHeader: string | null) => {
  return originHeader || process.env.NEXT_PUBLIC_APP_URL || "http://localhost:3000";
};

const getAudienceWhere = (garageId: string, audience: CampaignAudience, now: Date) => {
  const campaignCutoff = new Date(now.getTime() - CAMPAIGN_COOLDOWN_DAYS * 24 * 60 * 60 * 1000);
  const baseWhere: any = {
    garageId,
    emailOptOut: false,
    email: { not: "" },
    OR: [{ lastCampaignSentAt: null }, { lastCampaignSentAt: { lt: campaignCutoff } }],
  };

  if (audience === "mot_expiring") {
    const motCutoff = new Date(now.getTime() + 30 * 24 * 60 * 60 * 1000);
    baseWhere.vehicles = {
      some: {
        motExpiry: {
          gte: now,
          lte: motCutoff,
        },
      },
    };
  }

  if (audience === "service_due") {
    const serviceCutoff = new Date(now.getTime() - SERVICE_DUE_DAYS * 24 * 60 * 60 * 1000);
    baseWhere.vehicles = {
      some: {
        OR: [{ lastService: { lt: serviceCutoff } }, { lastService: null }],
      },
    };
  }

  if (audience === "inactive") {
    const inactiveCutoff = new Date(now.getTime() - INACTIVE_DAYS * 24 * 60 * 60 * 1000);
    baseWhere.updatedAt = { lt: inactiveCutoff };
  }

  return baseWhere;
};

const buildEmailHtml = (garageName: string, message: string, unsubscribeUrl: string) => {
  const safeMessage = message.replace(/\n/g, "<br>");

  return `
    <!DOCTYPE html>
    <html>
      <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <style>
          body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; line-height: 1.6; color: #1f2937; }
          .container { max-width: 600px; margin: 0 auto; background: #f9fafb; }
          .header { background: linear-gradient(135deg, #1d4ed8 0%, #1e40af 100%); color: white; padding: 28px 20px; text-align: center; }
          .content { background: white; padding: 28px 20px; }
          .message { background: #f3f4f6; padding: 16px; border-radius: 8px; }
          .footer { background: #f3f4f6; padding: 16px; text-align: center; font-size: 12px; color: #6b7280; }
          a { color: #1d4ed8; }
        </style>
      </head>
      <body>
        <div class="container">
          <div class="header">
            <h1 style="margin:0; font-size: 22px;">${garageName}</h1>
          </div>
          <div class="content">
            <div class="message">${safeMessage}</div>
          </div>
          <div class="footer">
            <p style="margin:0 0 6px 0;">You are receiving this email because you are a customer of ${garageName}.</p>
            <a href="${unsubscribeUrl}">Unsubscribe</a>
          </div>
        </div>
      </body>
    </html>
  `;
};

export const sendCampaign = async ({
  campaignId,
  originHeader,
}: {
  campaignId: string;
  originHeader: string | null;
}) => {
  const campaign = await prisma.campaign.findUnique({
    where: { id: campaignId },
    include: { garage: true },
  });

  if (!campaign) {
    throw new Error("Campaign not found");
  }

  if (campaign.channel !== "EMAIL") {
    throw new Error("SMS campaigns are not enabled yet");
  }

  const now = new Date();

  await prisma.campaign.update({
    where: { id: campaign.id },
    data: { status: "SENDING" },
  });

  const audience = (campaign.targetAudience || "all") as CampaignAudience;
  const where = getAudienceWhere(campaign.garageId, audience, now);

  const customers = await prisma.customer.findMany({
    where,
    select: {
      id: true,
      name: true,
      email: true,
      unsubscribeToken: true,
      emailOptOut: true,
      lastCampaignSentAt: true,
    },
  });

  if (customers.length === 0) {
    await prisma.campaign.update({
      where: { id: campaign.id },
      data: { status: "COMPLETED", sentCount: 0, failedCount: 0, skippedCount: 0 },
    });
    return { sentCount: 0, failedCount: 0, skippedCount: 0 };
  }

  let apiKey: string | null = await getApiKey("RESEND_API_KEY");
  let fromEmail: string | null = await getApiKey("RESEND_FROM_EMAIL");
  const fromName = (await getApiKey("RESEND_FROM_NAME")) || campaign.garage?.name || "GarageBoost";

  if (!apiKey) apiKey = process.env.RESEND_API_KEY || null;
  if (!fromEmail) fromEmail = process.env.RESEND_FROM_EMAIL || null;

  if (!apiKey || !fromEmail) {
    throw new Error("Email is not configured");
  }

  const origin = getOrigin(originHeader);
  const resend = new Resend(apiKey);
  const subject = (campaign.subject || campaign.name).trim();

  let sentCount = 0;
  let failedCount = 0;
  let skippedCount = 0;

  for (const customer of customers) {
    if (!customer.email || customer.emailOptOut) {
      skippedCount += 1;
      await prisma.campaignRecipient.create({
        data: {
          campaignId: campaign.id,
          customerId: customer.id,
          status: "SKIPPED",
        },
      });
      continue;
    }

    let token = customer.unsubscribeToken;
    if (!token) {
      token = crypto.randomUUID();
      await prisma.customer.update({
        where: { id: customer.id },
        data: { unsubscribeToken: token },
      });
    }

    const unsubscribeUrl = `${origin}/api/campaigns/unsubscribe?token=${token}`;

    try {
      const { error } = await resend.emails.send({
        from: `${fromName} <${fromEmail}>`,
        to: customer.email,
        subject: `${campaign.garage?.name || "GarageBoost"}: ${subject}`,
        html: buildEmailHtml(campaign.garage?.name || "GarageBoost", campaign.message, unsubscribeUrl),
      });

      if (error) {
        failedCount += 1;
        await prisma.campaignRecipient.create({
          data: {
            campaignId: campaign.id,
            customerId: customer.id,
            status: "FAILED",
            errorMessage: error.message,
          },
        });
        continue;
      }

      sentCount += 1;
      await prisma.customer.update({
        where: { id: customer.id },
        data: { lastCampaignSentAt: new Date() },
      });
      await prisma.campaignRecipient.create({
        data: {
          campaignId: campaign.id,
          customerId: customer.id,
          status: "SENT",
          sentAt: new Date(),
        },
      });
    } catch (sendError) {
      failedCount += 1;
      await prisma.campaignRecipient.create({
        data: {
          campaignId: campaign.id,
          customerId: customer.id,
          status: "FAILED",
          errorMessage: sendError instanceof Error ? sendError.message : "Send failed",
        },
      });
    }
  }

  await prisma.campaign.update({
    where: { id: campaign.id },
    data: {
      status: "COMPLETED",
      sentCount,
      failedCount,
      skippedCount,
    },
  });

  return { sentCount, failedCount, skippedCount };
};
